def process_graph(graph_data):
    # Create a mutable copy of the graph
    graph_copy = graph_data.copy()

    # Helper to find a node ID by its 'name' attribute
    def find_node_by_name(name):
        for nid, attr in graph_copy.nodes(data=True):
            if attr.get('name') == name:
                return nid
        return None

    # Remove the specified PORT node
    target_port_name = 'ju1.a2.m3.s3c1.p2'
    port_node_id = find_node_by_name(target_port_name)
    if port_node_id is not None:
        graph_copy.remove_node(port_node_id)

    # Identify the parent node whose children we need to rank
    parent_name = 'ju1.a2.m3.s3c1'
    parent_id = find_node_by_name(parent_name)
    if parent_id is None:
        # If parent not found, return empty results
        return {
            'type': 'list',
            'data': [],
            'updated_graph': __import__('networkx').readwrite.json_graph.node_link_data(graph_copy)
        }

    # Gather direct child nodes (edges with type RK_CONTAINS)
    direct_children = []
    for _, child, edata in graph_copy.out_edges(parent_id, data=True):
        if edata.get('type') == 'RK_CONTAINS':
            direct_children.append(child)

    # Helper to sum physical_capacity_bps for all PORT descendants of a node
    def sum_port_capacity(root_id):
        total = 0
        stack = [root_id]
        visited = set([root_id])
        while stack:
            current = stack.pop()
            cur_attr = graph_copy.nodes[current]
            if 'EK_PORT' in cur_attr.get('type', []):
                total += cur_attr.get('physical_capacity_bps', 0) or 0
            for _, nxt, eattr in graph_copy.out_edges(current, data=True):
                if eattr.get('type') == 'RK_CONTAINS' and nxt not in visited:
                    visited.add(nxt)
                    stack.append(nxt)
        return total

    # Build list of (node_name, total_capacity) tuples
    ranked_list = []
    for child_id in direct_children:
        child_attr = graph_copy.nodes[child_id]
        child_name = child_attr.get('name')
        capacity = sum_port_capacity(child_id)
        ranked_list.append([child_name, capacity])

    # Rank by capacity descending
    ranked_list.sort(key=lambda x: x[1], reverse=True)

    # Prepare the return object
    return {
        'type': 'list',
        'data': ranked_list,
        'updated_graph': __import__('networkx').readwrite.json_graph.node_link_data(graph_copy)
    }

